	update company_info set 
		officialseal_oriname = #{oriname}, officialseal_sysname = #{sysname},
		updated_at = CAST(SYSTIMESTAMP AS TIMESTAMP),
        updated_id = #{loginId}
	where company_seq = #{companySeq}

	update company_info set 
		officialmark_oriname = #{oriname}, Officialmark_sysname = #{sysname},
